class Twitter {
    private static class Tweet {
        int id;
        int time;
        Tweet(int id, int time) { this.id = id; this.time = time; }
    }

    private int timestamp;
    private Map<Integer, Set<Integer>> follows;
    private Map<Integer, List<Tweet>> tweets;

    public Twitter() {
        timestamp = 0;
        follows = new HashMap<>();
        tweets = new HashMap<>();
    }

    public void postTweet(int userId, int tweetId) {
        tweets.computeIfAbsent(userId, k -> new ArrayList<>()).add(new Tweet(tweetId, timestamp++));
        follows.computeIfAbsent(userId, k -> new HashSet<>()).add(userId);
    }

    public List<Integer> getNewsFeed(int userId) {
        PriorityQueue<Tweet> pq = new PriorityQueue<>((a, b) -> b.time - a.time);
        Set<Integer> users = follows.getOrDefault(userId, Set.of(userId));
        for (int uid : users) {
            List<Tweet> list = tweets.getOrDefault(uid, Collections.emptyList());
            for (int i = list.size() - 1; i >= 0 && i >= list.size() - 10; i--) {
                pq.offer(list.get(i));
            }
        }
        List<Integer> feed = new ArrayList<>();
        while (!pq.isEmpty() && feed.size() < 10) {
            feed.add(pq.poll().id);
        }
        return feed;
    }

    public void follow(int followerId, int followeeId) {
        follows.computeIfAbsent(followerId, k -> new HashSet<>()).add(followeeId);
    }

    public void unfollow(int followerId, int followeeId) {
        if (followerId != followeeId) {
            Set<Integer> set = follows.get(followerId);
            if (set != null) {
                set.remove(followeeId);
            }
        }
    }
}
